formula.expression:
if(empty({{notion:block_property:hgAe:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}}),
  "❌ 休眠",
  lets(
    /* Calculate days since last active */
    daysSinceActive, dateBetween(now(), {{notion:block_property:hgAe:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}}, "days"),
    /* Return activity level based on days */
    ifs(
      daysSinceActive < 7, "🔥 高频",
      daysSinceActive < 30, "✅ 正常",
      daysSinceActive < 90, "⚠️ 低频",
      "❌ 休眠"
    )
  )
)

lets(
  /* Extract trust level number from text like "L5 元老 ⭐⭐⭐⭐⭐" */
  trustLevelText, {{notion:block_property:ZnO~:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}}.split(" ").first().replaceAll("L", ""),
  trustLevel, if(empty(trustLevelText), 0, toNumber(trustLevelText)),
  /* Convert accuracy to decimal if it's a percentage (>1) */
  accuracy, if(empty({{notion:block_property:dTls:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}}), 0, if({{notion:block_property:dTls:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}} > 1, {{notion:block_property:dTls:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}} / 100, {{notion:block_property:dTls:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}})),
  /* Calculate individual score components */
  baseScore, (if(empty({{notion:block_property:mVZz:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}}), 0, {{notion:block_property:mVZz:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}})) * 0.4,
  qualityScore, accuracy * 0.3,
  trustScore, trustLevel * 20 * 0.3,
  penalty, (if(empty({{notion:block_property:Nz%5Bu:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}}), 0, {{notion:block_property:Nz%5Bu:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}})) * 5 + (if(empty({{notion:block_property:a%60j%3D:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}}), 0, {{notion:block_property:a%60j%3D:00000000-0000-0000-0000-000000000000:49f7125a-9c9f-81ec-9db8-00035916bff5}})) * 20,
  /* Calculate final contribution value */
  round(baseScore + qualityScore + trustScore - penalty, 2)
)
